<template>
	<div ref="containerRef" :class="`animated-content ${props.className}`">
		<slot />
	</div>
</template>

<script setup>
import { gsap } from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";
import { onMounted, onUnmounted, ref, watch } from "vue";
const props = defineProps({
  distance: { type: Number, required: false, default: 100 },
  direction: { type: String, required: false, default: "vertical" },
  reverse: { type: Boolean, required: false, default: false },
  duration: { type: Number, required: false, default: 0.8 },
  ease: { type: [String, Function], required: false, default: "power3.out" },
  initialOpacity: { type: Number, required: false, default: 0 },
  animateOpacity: { type: Boolean, required: false, default: true },
  scale: { type: Number, required: false, default: 1 },
  threshold: { type: Number, required: false, default: 0.1 },
  delay: { type: Number, required: false, default: 0 },
  className: { type: String, required: false, default: "" }
});
const emit = defineEmits(["complete"]);
gsap.registerPlugin(ScrollTrigger);
const containerRef = ref();
onMounted(() => {
  const el = containerRef.value;
  if (!el) return;
  const axis = props.direction === "horizontal" ? "x" : "y";
  const offset = props.reverse ? -props.distance : props.distance;
  const startPct = (1 - props.threshold) * 100;
  gsap.set(el, {
    [axis]: offset,
    scale: props.scale,
    opacity: props.animateOpacity ? props.initialOpacity : 1
  });
  gsap.to(el, {
    [axis]: 0,
    scale: 1,
    opacity: 1,
    duration: props.duration,
    ease: props.ease,
    delay: props.delay,
    onComplete: () => emit("complete"),
    scrollTrigger: {
      trigger: el,
      start: `top ${startPct}%`,
      toggleActions: "play none none none",
      once: true
    }
  });
});
watch(
  () => [
    props.distance,
    props.direction,
    props.reverse,
    props.duration,
    props.ease,
    props.initialOpacity,
    props.animateOpacity,
    props.scale,
    props.threshold,
    props.delay
  ],
  () => {
    const el = containerRef.value;
    if (!el) return;
    ScrollTrigger.getAll().forEach((t) => t.kill());
    gsap.killTweensOf(el);
    const axis = props.direction === "horizontal" ? "x" : "y";
    const offset = props.reverse ? -props.distance : props.distance;
    const startPct = (1 - props.threshold) * 100;
    gsap.set(el, {
      [axis]: offset,
      scale: props.scale,
      opacity: props.animateOpacity ? props.initialOpacity : 1
    });
    gsap.to(el, {
      [axis]: 0,
      scale: 1,
      opacity: 1,
      duration: props.duration,
      ease: props.ease,
      delay: props.delay,
      onComplete: () => emit("complete"),
      scrollTrigger: {
        trigger: el,
        start: `top ${startPct}%`,
        toggleActions: "play none none none",
        once: true
      }
    });
  },
  { deep: true }
);
onUnmounted(() => {
  const el = containerRef.value;
  if (el) {
    ScrollTrigger.getAll().forEach((t) => t.kill());
    gsap.killTweensOf(el);
  }
});
</script>
